#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vUv = mix(vUvOriginal,vUv,0.33);

vec2 d = uTexSize.zw;

vec2 uv_wolfram = vUvOriginal + vec2(0,1)*d*q1;

vec3 left = tex2d(sampler_fw_main, uv_wolfram - vec2(1,0)*d).y;
vec3 right = tex2d(sampler_fw_main, uv_wolfram + vec2(1,0)*d).y;
vec3 it = tex2d(sampler_fw_main, uv_wolfram).y;

left = left > 0.5;
right = right >0.5;
it = it > 0.5;
float wolfram110 = left*( it*(1-right) + (1-it)*right) + (1-left)*(1-(1-left)*(1-it)*(1-right));
float wolfram90 = left*(1-right) + (1-left)*right;
float wolfram150 = left*(it==right) + (1-left)*(it!=right);

ret.y = wolfram90;

    vec2 help_uv = 0.5 + (vUv-0.5)*uAspect.wz;
    float zoom = 0.6;
    vec2 center = vec2(0,0.7);
    vec2 m = center + (help_uv-0.5)*zoom;

 int iter = 30;

 vec2 c = vec2(0.3,0.47);

 for (int i = 0; i < iter && dot(m,m)<5; i++)
 {
    m = vec2(m.x*m.x - m.y*m.y, m.x*m.y*2)+c;
 }

float dot = dot(m,m);


ret.x = dot*0.04 + (0.18-m.x*0.08 - m.y*0.1);

vUv = mix(vUvOriginal,vUv,.02);
    d = uTexSize.zw * 8;
    vec3 dx = ( 2*GetBlur1(vUv + vec2(1,0)*d) - 2*GetBlur1(vUv-vec2(1,0)*d) )*0.5;
    vec3 dy = ( 2*GetBlur1(vUv + vec2(0,1)*d) - 2*GetBlur1(vUv-vec2(0,1)*d) )*0.5;

ret.z = tex2d(sampler_fc_main, vUv + vec2(dx.z,dy.z)*uTexSize.zw).z;
vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1.2 + rand_frame.xy;
ret.z += (texture(sampler_noise_lq, dither_uv).xyz-0.5) *0.04 - 0.002;
ret.z += -ret.y*0.008 - ret.x*0.009  + 0.004;



  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvo = 0.5 + (vUv-0.5)*vec2(1.1,0.81);
factorA = vUv-vec2(1-0.5,0.5);
factorB = vec2(0,-1024);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
numerator = vec2(1,0);
denominator = product;
fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,   // the fractions real part
                   numerator.y*denominator.x - numerator.x*denominator.y)/  // the fractions imaginary part
                   (denominator.x*denominator.x + denominator.y*denominator.y);
vUv = fraction.yx*vec2(-1,1)*100;
vUv = mix(0.5 + (uvo-0.5)*2,vUv+0.5,0.5);
vUv = 0.5 + (1.0 - abs( fract( vUv * 0.5 ) * 2 - 1.0 )-0.5)*0.98; // Eo.S. mirror code with cutted borders
// ***** Flexis rotating caleidoscope code *****

vec2 cntr = vec2(q23,q24); float sin = q21; float cos = q22; float scale = q25;
vec2 uv_r = (vUv-cntr)*uAspect.xy;
       uv_r = scale*vec2( cos*uv_r.x - sin*uv_r.y, sin*uv_r.x + cos*uv_r.y); // rotation
       uv_r = cntr + uv_r*uAspect.zw;
       uv_r = 1.0 - abs( fract( uv_r * 0.5 ) * 2.0 - 1.0 ); // mirror

sin = q27; cos = q28; scale = q26;
vec2 uv_rr = (uv_r-cntr)*uAspect.xy;
       uv_rr = scale*vec2( cos*uv_rr.x - sin*uv_rr.y, sin*uv_rr.x + cos*uv_rr.y); // counter-rotation
       uv_rr = cntr + (uv_rr)*uAspect.zw;

vec2 caleidoscope_uv = uv_rr;

// *****

vUv = uv_rr;


vec2 d = uTexSize.zw;
vec3 dx = (2*GetPixel(vUv + vec2(1,0)*d) - 2*GetPixel(vUv + vec2(-1,0)*d))*0.5;
vec3 dy = (2*GetPixel(vUv + vec2(0,1)*d) - 2*GetPixel(vUv + vec2(0,-1)*d))*0.5;

ret = mix(vec3(0,0,0),vec3(1,1,1)*pow(hue_shader,4),(-dx.z+dy.z)*8 + 0.1 )+ GetPixel(vUv).z*0.85 - 0.08;


  fragColor = ret;
}
